insert into jst_appointment_writeoff_item (
    appointment_id, team_appointment_id, item_type, item_name, qr_code, status,
    writeoff_time, writeoff_user_id, writeoff_terminal, writeoff_qty, total_qty,
    create_by, create_time, update_by, update_time, remark, del_flag
) values (
    #{item.appointmentId}, #{item.teamAppointmentId}, #{item.itemType}, #{item.itemName}, #{item.qrCode},
    #{item.status}, #{item.writeoffTime}, #{item.writeoffUserId}, #{item.writeoffTerminal},
    #{item.writeoffQty}, #{item.totalQty}, #{item.createBy}, #{item.createTime}, #{item.updateBy},
    #{item.updateTime}, #{item.remark}, #{item.delFlag}
)

mapper.update:
update jst_appointment_writeoff_item
set status = 'used',
    writeoff_qty = #{targetWriteoffQty},
    writeoff_time = #{writeoffTime},
    writeoff_user_id = #{writeoffUserId},
    writeoff_terminal = #{writeoffTerminal},
    update_by = #{updateBy},
    update_time = #{updateTime}
where writeoff_item_id = #{writeoffItemId}
  and status = #{expectedStatus}
  and writeoff_qty = #{expectedWriteoffQty}
  and del_flag = '0'

mapper.select:
select wi.writeoff_item_id as writeoffItemId, c.contest_id as contestId, c.contest_name as contestName, t.team_name as teamName, p.name as memberName, wi.item_type as itemType, wi.item_name as itemName, wi.status as status, ar.session_code as sessionCode, ar.appointment_date as appointmentDate, wi.writeoff_time as writeoffTime, wi.writeoff_terminal as writeoffTerminal from jst_appointment_writeoff_item wi inner join jst_appointment_record ar on ar.appointment_id = wi.appointment_id and ar.del_flag = '0' inner join jst_contest c on c.contest_id = ar.contest_id and c.del_flag = '0' left join jst_team_appointment t on t.team_appointment_id = wi.team_appointment_id and t.del_flag = '0' left join jst_participant p on p.participant_id = ar.participant_id and p.del_flag = '0' where wi.del_flag = '0' and wi.status = 'used'
and c.partner_id = #{partnerId}
and c.contest_id = #{query.contestId}
and wi.writeoff_time >= #{query.beginDate}
and wi.writeoff_time <= #{query.endDate}
order by wi.writeoff_time desc, wi.writeoff_item_id desc
